import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Printer, Download, Zap, Wrench } from 'lucide-react';
import { ScheduleOverride } from '../types';
import { loadOverrides } from '../services/storage';
import { BottomMenu } from '../components/BottomMenu';

interface EmployeeBase {
  name: string;
  role: string;
  referenceDate: Date;
  vacations?: { start: Date; end: Date }[];
}

const PrintableCalendarPage: React.FC = () => {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [overrides, setOverrides] = useState<ScheduleOverride[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      setIsLoading(true);
      const data = await loadOverrides();
      setOverrides(data);
      setIsLoading(false);
    };
    fetch();
  }, []);

  const employeesConfig: EmployeeBase[] = [
    { name: 'Valci Jacinto', role: 'Mecânico', referenceDate: new Date(2025, 11, 1) }, 
    { name: 'Mauro Luiz', role: 'Eletricista', referenceDate: new Date(2025, 11, 1) }, 
    { name: 'Antonio Marcos', role: 'Eletricista', referenceDate: new Date(2025, 11, 2) }, 
    { name: 'Adriano Pinto', role: 'Eletricista', referenceDate: new Date(2025, 11, 3) }, 
    { name: 'Mário de Souza', role: 'Mecânico', referenceDate: new Date(2025, 11, 4) }, 
    { 
      name: 'Manuel Gonçalves', 
      role: 'Mecânico', 
      referenceDate: new Date(2025, 11, 5),
      vacations: [
        { start: new Date(2025, 11, 22), end: new Date(2026, 0, 10) } 
      ]
    }, 
    { name: 'Alan Pereira', role: 'Mecânico', referenceDate: new Date(2025, 11, 6) }, 
  ];

  const monthNames = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
  ];

  const getDaysInMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  const getFirstDayOfMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth(), 1).getDay();

  const isEmployeeOnVacation = (employee: EmployeeBase, date: Date) => {
    if (!employee.vacations) return false;
    const target = new Date(date).setHours(0,0,0,0);
    return employee.vacations.some(v => {
      const start = new Date(v.start).setHours(0,0,0,0);
      const end = new Date(v.end).setHours(0,0,0,0);
      return target >= start && target <= end;
    });
  };

  const isRegularDayOff = (employee: EmployeeBase, date: Date) => {
    const target = new Date(date).setHours(0,0,0,0);
    const ref = new Date(employee.referenceDate).setHours(0,0,0,0);
    const diffDays = Math.round((target - ref) / (1000 * 3600 * 24));
    return ((diffDays % 6) + 6) % 6 === 0;
  };

  const getWhoIsOff = (date: Date) => {
    const list: { name: string, role: string, type: 'regular' | 'vacation' | 'extra' }[] = [];
    const dateStr = date.toISOString().split('T')[0];

    employeesConfig.forEach(emp => {
      const override = overrides.find(o => o.date === dateStr && o.employeeName === emp.name);

      if (override) {
        if (override.type === 'extra_day_off') {
          list.push({ name: emp.name, role: emp.role, type: 'extra' });
        }
        // If it's emergency_work, they are NOT off, so we skip adding them to the list
      } else if (isEmployeeOnVacation(emp, date)) {
        list.push({ name: emp.name, role: emp.role, type: 'vacation' });
      } else if (isRegularDayOff(emp, date)) {
        list.push({ name: emp.name, role: emp.role, type: 'regular' });
      }
    });
    return list;
  };

  const daysInMonth = getDaysInMonth(currentMonth);
  const startDay = getFirstDayOfMonth(currentMonth);
  const calendarDays = [];
  for (let i = 0; i < startDay; i++) calendarDays.push(null);
  for (let i = 1; i <= daysInMonth; i++) {
    calendarDays.push(new Date(currentMonth.getFullYear(), currentMonth.getMonth(), i));
  }

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="flex flex-col h-full bg-[#0f172a] text-white print:bg-white print:text-black">
      {/* Print styles */}
      <style>{`
        @media print {
          @page { size: A4 landscape; margin: 5mm; }
          body { background: white !important; color: black !important; }
          .no-print { display: none !important; }
          .print-border { border: 1px solid #000 !important; }
          .print-bg-regular { background-color: #ffedd5 !important; border-left: 4px solid #f97316 !important; }
          .print-bg-vacation { background-color: #dbeafe !important; border-left: 4px solid #3b82f6 !important; }
          .print-bg-extra { background-color: #ccfbf1 !important; border-left: 4px solid #14b8a6 !important; }
          .calendar-grid { grid-template-rows: repeat(auto-fill, minmax(100px, 1fr)) !important; }
        }
      `}</style>

      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-slate-800 no-print">
        <div className="flex items-center gap-4">
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1))} className="p-2 hover:bg-slate-800 rounded-full transition-colors">
            <ChevronLeft />
          </button>
          <h1 className="text-xl font-bold min-w-[180px] text-center">
            {monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}
          </h1>
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1))} className="p-2 hover:bg-slate-800 rounded-full transition-colors">
            <ChevronRight />
          </button>
        </div>

        <button 
          onClick={handlePrint}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold transition-all shadow-lg active:scale-95"
        >
          <Download className="w-4 h-4" />
          Baixar PDF / Imprimir
        </button>
      </div>

      {/* Print Title (Only visible when printing) */}
      <div className="hidden print:block text-center mb-4">
        <h1 className="text-2xl font-bold uppercase tracking-widest">Escala de Folgas - {monthNames[currentMonth.getMonth()]} / {currentMonth.getFullYear()}</h1>
        <p className="text-sm">HR Flow - Gestão de Manutenção</p>
      </div>

      {/* Legend - no print */}
      <div className="px-6 py-2 flex gap-4 no-print text-[10px] uppercase font-bold text-slate-400">
        <div className="flex items-center gap-1"><span className="w-2 h-2 bg-orange-500 rounded-full"></span> 5x1 Normal</div>
        <div className="flex items-center gap-1"><span className="w-2 h-2 bg-blue-500 rounded-full"></span> Férias</div>
        <div className="flex items-center gap-1"><span className="w-2 h-2 bg-teal-500 rounded-full"></span> Folga Extra</div>
      </div>

      {/* Calendar Table Style */}
      <div className="flex-1 overflow-auto p-4 md:p-6 mb-16 print:mb-0 print:p-0">
        <div className="grid grid-cols-7 border-t border-l border-slate-800 print:border-black">
          {['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].map(day => (
            <div key={day} className="bg-slate-800/50 py-2 text-center text-xs font-bold uppercase border-r border-b border-slate-800 print:bg-gray-100 print:border-black print:text-black">
              {day}
            </div>
          ))}

          {calendarDays.map((date, idx) => {
            if (!date) return <div key={`empty-${idx}`} className="bg-slate-900/20 border-r border-b border-slate-800 print:border-black"></div>;

            const whoIsOff = getWhoIsOff(date);
            const isToday = new Date().setHours(0,0,0,0) === date.setHours(0,0,0,0);

            return (
              <div key={idx} className={`min-h-[120px] p-1 border-r border-b border-slate-800 flex flex-col gap-1 print:border-black print:min-h-[90px] ${isToday ? 'bg-blue-900/10' : ''}`}>
                <div className={`text-right text-xs font-bold px-1 mb-1 ${isToday ? 'text-blue-400' : 'text-slate-500 print:text-black'}`}>
                  {date.getDate()}
                </div>

                <div className="flex flex-col gap-1 overflow-hidden">
                  {whoIsOff.map((off, oIdx) => (
                    <div 
                      key={oIdx} 
                      className={`text-[9px] md:text-[10px] px-1.5 py-1 rounded border-l-2 leading-tight flex items-center gap-1 truncate
                        ${off.type === 'regular' ? 'bg-orange-500/20 text-orange-200 border-orange-500 print-bg-regular' : ''}
                        ${off.type === 'vacation' ? 'bg-blue-500/20 text-blue-200 border-blue-500 print-bg-vacation' : ''}
                        ${off.type === 'extra' ? 'bg-teal-500/20 text-teal-200 border-teal-500 print-bg-extra' : ''}
                      `}
                    >
                      {off.role.toLowerCase().includes('eletricista') ? <Zap className="w-2.5 h-2.5 shrink-0" /> : <Wrench className="w-2.5 h-2.5 shrink-0" />}
                      <span className="font-bold print:text-black">{off.name.split(' ')[0]} {off.name.split(' ')[1] || ''}</span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <BottomMenu />
    </div>
  );
};

