import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Printer, Download, Zap, Wrench } from 'lucide-react';
import { ScheduleOverride } from '../types';
import { loadOverrides } from '../services/storage';
import { BottomMenu } from '../components/BottomMenu';

interface EmployeeBase {
  name: string;
  role: string;
  referenceDate: Date;
  vacations?: { start: Date; end: Date }[];
}

const PrintableCalendarPage: React.FC = () => {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [overrides, setOverrides] = useState<ScheduleOverride[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      setIsLoading(true);
      const data = await loadOverrides();
      setOverrides(data);
      setIsLoading(false);
    };
    fetch();
  }, []);

  const employeesConfig: EmployeeBase[] = [
    { name: 'Valci Jacinto', role: 'Mecânico', referenceDate: new Date(2025, 11, 1) }, 
    { name: 'Mauro Luiz', role: 'Eletricista', referenceDate: new Date(2025, 11, 1) }, 
    { name: 'Antonio Marcos', role: 'Eletricista', referenceDate: new Date(2025, 11, 2) }, 
    { name: 'Adriano Pinto', role: 'Eletricista', referenceDate: new Date(2025, 11, 3) }, 
    { name: 'Mário de Souza', role: 'Mecânico', referenceDate: new Date(2025, 11, 4) }, 
    { 
      name: 'Manuel Gonçalves', 
      role: 'Mecânico', 
      referenceDate: new Date(2025, 11, 5),
      vacations: [
        { start: new Date(2025, 11, 22), end: new Date(2026, 0, 10) } 
      ]
    }, 
    { name: 'Alan Pereira', role: 'Mecânico', referenceDate: new Date(2025, 11, 6) }, 
  ];

  const monthNames = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
  ];

  const getDaysInMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  const getFirstDayOfMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth(), 1).getDay();

  const isEmployeeOnVacation = (employee: EmployeeBase, date: Date) => {
    if (!employee.vacations) return false;
    const target = new Date(date).setHours(0,0,0,0);
    return employee.vacations.some(v => {
      const start = new Date(v.start).setHours(0,0,0,0);
      const end = new Date(v.end).setHours(0,0,0,0);
      return target >= start && target <= end;
    });
  };

  const isRegularDayOff = (employee: EmployeeBase, date: Date) => {
    const target = new Date(date).setHours(0,0,0,0);
    const ref = new Date(employee.referenceDate).setHours(0,0,0,0);
    const diffDays = Math.round((target - ref) / (1000 * 3600 * 24));
    return ((diffDays % 6) + 6) % 6 === 0;
  };

  const getWhoIsOff = (date: Date) => {
    const list: { name: string, role: string, type: 'regular' | 'vacation' | 'extra' }[] = [];
    const dateStr = date.toISOString().split('T')[0];

    employeesConfig.forEach(emp => {
      const override = overrides.find(o => o.date === dateStr && o.employeeName === emp.name);

      if (override) {
        if (override.type === 'extra_day_off') {
          list.push({ name: emp.name, role: emp.role, type: 'extra' });
        }
      } else if (isEmployeeOnVacation(emp, date)) {
        list.push({ name: emp.name, role: emp.role, type: 'vacation' });
      } else if (isRegularDayOff(emp, date)) {
        list.push({ name: emp.name, role: emp.role, type: 'regular' });
      }
    });
    return list;
  };

  const daysInMonth = getDaysInMonth(currentMonth);
  const startDay = getFirstDayOfMonth(currentMonth);
  const calendarDays = [];
  for (let i = 0; i < startDay; i++) calendarDays.push(null);
  for (let i = 1; i <= daysInMonth; i++) {
    calendarDays.push(new Date(currentMonth.getFullYear(), currentMonth.getMonth(), i));
  }

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="flex flex-col h-full bg-[#0f172a] text-white print:bg-white print:text-black min-h-screen">
      <style>{`
        @media print {
          @page { size: A4 landscape; margin: 0; }
          body { background: white !important; color: black !important; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
          .no-print { display: none !important; }
          .print-grid { border: 1.5pt solid black !important; }
          .print-cell { border: 0.5pt solid black !important; min-height: 2.8cm !important; }
          .print-bg-regular { background-color: #ffedd5 !important; border-left: 6pt solid #f97316 !important; color: black !important; }
          .print-bg-vacation { background-color: #dbeafe !important; border-left: 6pt solid #3b82f6 !important; color: black !important; }
          .print-bg-extra { background-color: #ccfbf1 !important; border-left: 6pt solid #14b8a6 !important; color: black !important; }
          .print-header { background-color: #f1f5f9 !important; border-bottom: 1.5pt solid black !important; }
          .print-content { padding: 10mm !important; }
        }
      `}</style>

      {/* Header - Hidden on print */}
      <div className="flex items-center justify-between px-8 py-6 border-b border-slate-800 no-print sticky top-0 bg-[#0f172a] z-50">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1))} className="p-3 hover:bg-slate-800 rounded-full transition-colors">
              <ChevronLeft className="w-6 h-6" />
            </button>
            <h1 className="text-2xl font-black min-w-[220px] text-center tracking-tight">
              {monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}
            </h1>
            <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1))} className="p-3 hover:bg-slate-800 rounded-full transition-colors">
              <ChevronRight className="w-6 h-6" />
            </button>
          </div>
        </div>

        <button 
          onClick={handlePrint}
          className="flex items-center gap-3 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl font-bold transition-all shadow-xl active:scale-95 group"
        >
          <Printer className="w-5 h-5 group-hover:animate-bounce" />
          Gerar Escala de Parede (PDF)
        </button>
      </div>

      <div className="print-content flex-1 flex flex-col p-8 overflow-auto">
        {/* Title for print */}
        <div className="hidden print:flex flex-col items-center mb-8 border-b-2 border-black pb-4">
          <h1 className="text-4xl font-black uppercase tracking-tighter italic">Quadro de Folgas Mensal</h1>
          <p className="text-xl font-bold text-slate-700">{monthNames[currentMonth.getMonth()]} de {currentMonth.getFullYear()}</p>
        </div>

        {/* Legend */}
        <div className="flex gap-8 mb-6 no-print">
           <div className="flex items-center gap-2 font-bold text-xs"><span className="w-4 h-4 bg-orange-500 rounded shadow"></span> ESCALA 5x1</div>
           <div className="flex items-center gap-2 font-bold text-xs"><span className="w-4 h-4 bg-blue-500 rounded shadow"></span> FÉRIAS</div>
           <div className="flex items-center gap-2 font-bold text-xs"><span className="w-4 h-4 bg-teal-500 rounded shadow"></span> COMPENSAÇÃO (EXTRA)</div>
        </div>

        {/* Calendar Grid */}
        <div className="print-grid grid grid-cols-7 border-t border-l border-slate-700 shadow-2xl rounded-sm overflow-hidden flex-1">
          {['DOMINGO', 'SEGUNDA', 'TERÇA', 'QUARTA', 'QUINTA', 'SEXTA', 'SÁBADO'].map(day => (
            <div key={day} className="print-header bg-slate-800/80 py-4 text-center text-xs font-black uppercase tracking-widest border-r border-b border-slate-700">
              {day}
            </div>
          ))}

          {calendarDays.map((date, idx) => {
            if (!date) return <div key={`empty-${idx}`} className="bg-slate-900/40 border-r border-b border-slate-700"></div>;

            const whoIsOff = getWhoIsOff(date);
            const isToday = new Date().setHours(0,0,0,0) === date.setHours(0,0,0,0);

            return (
              <div key={idx} className={`print-cell p-2 border-r border-b border-slate-700 flex flex-col gap-2 min-h-[140px] bg-slate-900/20 transition-colors ${isToday ? 'ring-2 ring-blue-600 ring-inset bg-blue-900/10' : ''}`}>
                <div className={`text-right text-lg font-black ${isToday ? 'text-blue-500' : 'text-slate-500 print:text-black opacity-40'}`}>
                  {date.getDate()}
                </div>

                <div className="flex flex-col gap-1.5">
                  {whoIsOff.map((off, oIdx) => (
                    <div 
                      key={oIdx} 
                      className={`text-[10px] md:text-xs px-3 py-2 rounded-md font-black uppercase tracking-tighter flex items-center gap-2 border shadow-sm
                        ${off.type === 'regular' ? 'bg-orange-500/10 text-orange-400 border-orange-500/30 print-bg-regular' : ''}
                        ${off.type === 'vacation' ? 'bg-blue-500/10 text-blue-400 border-blue-500/30 print-bg-vacation' : ''}
                        ${off.type === 'extra' ? 'bg-teal-500/10 text-teal-400 border-teal-500/30 print-bg-extra' : ''}
                      `}
                    >
                      <span className="shrink-0">{off.role.toLowerCase().includes('eletricista') ? <Zap className="w-3 h-3" /> : <Wrench className="w-3 h-3" />}</span>
                      <span className="truncate">{off.name}</span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="md:hidden">
        <BottomMenu />
      </div>
    </div>
  );
};

