          .print-bg-vacation { background-color: #dbeafe !important; border-left: 5px solid #3b82f6 !important; }
          .print-bg-extra { background-color: #ccfbf1 !important; border-left: 5px solid #14b8a6 !important; }
          .print-text { color: black !important; font-weight: bold !important; }
          .sidebar-container { display: none !important; }
        }
      `}</style>

      {/* Control Header */}
      <div className="flex items-center justify-between px-6 py-4 bg-[#0f172a] border-b border-slate-800 no-print sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1))} className="p-2 hover:bg-slate-800 rounded-full">
            <ChevronLeft className="w-6 h-6" />
          </button>
          <h1 className="text-xl font-bold min-w-[200px] text-center">
            {monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}
          </h1>
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1))} className="p-2 hover:bg-slate-800 rounded-full">
            <ChevronRight className="w-6 h-6" />
          </button>
        </div>

        <button 
          onClick={handlePrint}
          disabled={isPreparing}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-bold transition-all shadow-lg active:scale-95 disabled:opacity-50"
        >
          {isPreparing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
          {isPreparing ? 'Preparando...' : 'Baixar Escala (PDF)'}
        </button>
      </div>

      <div className="print-container flex-1 overflow-auto p-6 flex flex-col gap-6">
        {/* Title for PDF */}
        <div className="hidden print:block text-center border-b-2 border-black pb-4 mb-2">
          <h1 className="text-3xl font-black uppercase">Escala Mensal de Manutenção</h1>
          <p className="text-lg font-bold">{monthNames[currentMonth.getMonth()]} / {currentMonth.getFullYear()}</p>
        </div>

        {/* Legend */}
        <div className="flex gap-6 no-print">
          <div className="flex items-center gap-2 text-[10px] font-bold"><span className="w-3 h-3 bg-orange-500 rounded"></span> FOLGA 5x1</div>
          <div className="flex items-center gap-2 text-[10px] font-bold"><span className="w-3 h-3 bg-blue-500 rounded"></span> FÉRIAS</div>
          <div className="flex items-center gap-2 text-[10px] font-bold"><span className="w-3 h-3 bg-teal-500 rounded"></span> FOLGA EXTRA</div>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-7 border-t border-l border-slate-700 print:border-black flex-1 min-h-[600px]">
          {['DOM', 'SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SÁB'].map(day => (
            <div key={day} className="bg-slate-800/50 py-3 text-center text-xs font-black border-r border-b border-slate-700 print:bg-gray-100 print:border-black print:text-black">
              {day}
            </div>
          ))}

          {calendarDays.map((date, idx) => {
            if (!date) return <div key={`empty-${idx}`} className="bg-slate-900/20 border-r border-b border-slate-700 print:border-black"></div>;

            const whoIsOff = getWhoIsOff(date);
            const isToday = new Date().setHours(0,0,0,0) === date.setHours(0,0,0,0);

            return (
              <div key={idx} className={`print-cell p-2 border-r border-b border-slate-700 flex flex-col gap-1 min-h-[120px] bg-slate-900/10 print:min-h-[100px] print:border-black ${isToday ? 'bg-blue-600/10 ring-1 ring-blue-500 ring-inset' : ''}`}>
                <span className={`text-right text-sm font-bold block mb-1 ${isToday ? 'text-blue-500' : 'text-slate-500 print:text-black'}`}>
                  {date.getDate()}
                </span>

                <div className="flex flex-col gap-1">
                  {whoIsOff.map((off, oIdx) => (
                    <div 
                      key={oIdx} 
                      className={`text-[9px] px-2 py-1 rounded border-l-2 font-bold uppercase truncate flex items-center gap-1
                        ${off.type === 'regular' ? 'bg-orange-500/10 text-orange-400 border-orange-500 print-bg-regular print-text' : ''}
                        ${off.type === 'vacation' ? 'bg-blue-500/10 text-blue-400 border-blue-500 print-bg-vacation print-text' : ''}
                        ${off.type === 'extra' ? 'bg-teal-500/10 text-teal-400 border-teal-500 print-bg-extra print-text' : ''}
                      `}
                    >
                      {off.role.toLowerCase().includes('eletricista') ? <Zap className="w-2.5 h-2.5" /> : <Wrench className="w-2.5 h-2.5" />}
                      {off.name.split(' ')[0]}
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="md:hidden no-print">
        <BottomMenu />
      </div>
    </div>
  );
};

