                      <button onClick={() => { setOverrideType('extra_day_off'); setOverrideEmployee(''); }} className={`flex-1 py-2 text-xs font-bold rounded-md transition-colors ${overrideType === 'extra_day_off' ? 'bg-teal-600 text-white' : 'text-slate-400 hover:text-white'}`}>Folga Extra</button>
                  </div>
                  <div className="space-y-4">
                      <div><label className="block text-xs font-medium text-slate-400 mb-1">Dia Selecionado</label><div className="text-white font-medium bg-[#0f172a] p-2 rounded-lg border border-slate-800">{formattedSelectedDate}</div></div>
