                      <button disabled={!overrideEmployee} onClick={handleAddOverride} className={`w-full text-white font-bold py-3 rounded-xl disabled:opacity-50 flex items-center justify-center gap-2 mt-2 ${overrideType === 'emergency_work' ? 'bg-purple-600 hover:bg-purple-700' : 'bg-teal-600 hover:bg-teal-700'}`}>
                          <Save className="w-5 h-5" /> Salvar Ajuste
                      </button>
