import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Search, Plus, Zap, Wrench } from 'lucide-react';
import { Employee, EmployeeStatus, ScheduleOverride } from '../types';
import { BottomMenu } from '../components/BottomMenu';
import { loadOverrides } from '../services/storage';

interface ExtendedEmployee extends Employee {
  referenceDate: Date;
  vacations?: { start: Date; end: Date }[];
}

const EmployeeListPage: React.FC = () => {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');
  const [today] = useState(new Date());
  const [overrides, setOverrides] = useState<ScheduleOverride[]>([]);

  useEffect(() => {
    const fetch = async () => {
        const data = await loadOverrides();
        setOverrides(data);
    };
    fetch();
  }, []);

  const employeesConfig: ExtendedEmployee[] = [
    { id: '1', name: 'Adriano Pinto', role: 'Eletricista Senior', avatar: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=150&h=150&fit=crop', status: EmployeeStatus.AVAILABLE, referenceDate: new Date(2025, 11, 3) },
    { id: '2', name: 'Alan Pereira', role: 'Mecânico de Manutenção', avatar: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=150&h=150&fit=crop', status: EmployeeStatus.AVAILABLE, referenceDate: new Date(2025, 11, 6) },
    { id: '3', name: 'Antonio Marcos', role: 'Eletricista', avatar: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=150&h=150&fit=crop', status: EmployeeStatus.AVAILABLE, referenceDate: new Date(2025, 11, 2) },
    { id: '4', name: 'Valci Jacinto', role: 'Líder Mecânico', avatar: 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?w=150&h=150&fit=crop', status: EmployeeStatus.AVAILABLE, referenceDate: new Date(2025, 11, 1) },
    { id: '5', name: 'Manuel Gonçalves', role: 'Mecânico Auxiliar', avatar: 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?w=150&h=150&fit=crop', status: EmployeeStatus.AVAILABLE, referenceDate: new Date(2025, 11, 5), vacations: [{ start: new Date(2025, 11, 22), end: new Date(2026, 0, 10) }] },
    { id: '6', name: 'Mário de Souza', role: 'Mecânico Industrial', avatar: 'https://images.unsplash.com/photo-1539571696357-5a69c17a67c6?w=150&h=150&fit=crop', status: EmployeeStatus.AVAILABLE, referenceDate: new Date(2025, 11, 4) },
    { id: '7', name: 'Mauro Luiz', role: 'Técnico Eletricista', avatar: 'https://images.unsplash.com/photo-1552374196-c4e7ffc6e126?w=150&h=150&fit=crop', status: EmployeeStatus.AVAILABLE, referenceDate: new Date(2025, 11, 1) }
  ];

  const getCalculatedStatus = (emp: ExtendedEmployee): EmployeeStatus => {
    const checkDate = new Date(today);
    checkDate.setHours(0,0,0,0);
    const dateStr = checkDate.toISOString().split('T')[0];
    const override = overrides.find(o => o.date === dateStr && o.employeeName === emp.name);
    if (override) {
        if (override.type === 'emergency_work') return EmployeeStatus.EXTRA_WORK;
        if (override.type === 'extra_day_off') return EmployeeStatus.EXTRA_OFF;
    }
    if (emp.vacations) {
      const isOnVacation = emp.vacations.some(v => {
        const start = new Date(v.start).setHours(0,0,0,0);
        const end = new Date(v.end).setHours(0,0,0,0);
        return checkDate.getTime() >= start && checkDate.getTime() <= end;
      });
      if (isOnVacation) return EmployeeStatus.VACATION;
    }
    const ref = new Date(emp.referenceDate);
    ref.setHours(0,0,0,0);
    const diffDays = Math.round((checkDate.getTime() - ref.getTime()) / (1000 * 3600 * 24));
    if ((((diffDays % 6) + 6) % 6) === 0) return EmployeeStatus.DAY_OFF;
    return EmployeeStatus.AVAILABLE;
  };

  const filteredEmployees = employeesConfig.filter(emp =>
    emp.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getStatusDot = (status: EmployeeStatus) => {
     switch (status) {
      case EmployeeStatus.AVAILABLE: return 'bg-green-400';
      case EmployeeStatus.VACATION: return 'bg-blue-400';
      case EmployeeStatus.DAY_OFF: return 'bg-orange-400';
      case EmployeeStatus.EXTRA_WORK: return 'bg-purple-500';
      case EmployeeStatus.EXTRA_OFF: return 'bg-teal-400';
      default: return 'bg-gray-400';
    }
  }

  return (
    <div className="flex flex-col h-full bg-[#0f172a] text-white relative">
        <div className="flex items-center justify-between px-6 py-8 bg-[#0f172a] sticky top-0 z-30">
           <div>
             <h1 className="text-3xl font-bold text-white">Equipe Técnica</h1>
             <p className="text-slate-400 text-sm mt-1">Status em tempo real</p>
           </div>
           <button onClick={() => navigate('/request')} className="bg-blue-600 p-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg"><Plus className="w-6 h-6 text-white" /></button>
        </div>
      <div className="px-6 mb-6">
        <div className="relative group">
          <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-slate-500 w-5 h-5 group-focus-within:text-blue-500 transition-colors" />
          <input type="text" placeholder="Nome ou cargo..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-[#1e293b] text-white pl-12 pr-4 py-4 rounded-2xl focus:outline-none focus:ring-2 focus:ring-blue-600 border border-slate-800 placeholder-slate-500 transition-all" />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto px-6 pb-24 space-y-3">
        {filteredEmployees.map((emp) => {
          const currentStatus = getCalculatedStatus(emp);
          return (
            <div key={emp.id} onClick={() => navigate(`/employee/${emp.id}`)} className="flex items-center justify-between p-4 rounded-2xl bg-[#1e293b]/40 border border-transparent hover:border-slate-700 hover:bg-[#1e293b] transition-all cursor-pointer group">
              <div className="flex items-center gap-4">
                <div className="relative">
                  <div className="w-14 h-14 rounded-full overflow-hidden border-2 border-slate-700 shadow-md">
                    <img src={emp.avatar} alt={emp.name} className="w-full h-full object-cover" />
                  </div>
                  <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-4 border-[#1e293b] ${getStatusDot(currentStatus)}`}></div>
                </div>
                <div>
                  <h3 className="font-bold text-slate-100 group-hover:text-white">{emp.name}</h3>
                  <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">{emp.role}</p>
                </div>
              </div>
              <div className={`px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-widest ${currentStatus === EmployeeStatus.AVAILABLE ? 'bg-green-500/10 text-green-400' : currentStatus === EmployeeStatus.DAY_OFF ? 'bg-orange-500/10 text-orange-400' : currentStatus === EmployeeStatus.VACATION ? 'bg-blue-500/10 text-blue-400' : currentStatus === EmployeeStatus.EXTRA_WORK ? 'bg-purple-500/10 text-purple-400' : 'bg-teal-500/10 text-teal-400'}`}>{currentStatus}</div>
            </div>
          );
        })}
      </div>
      <BottomMenu />
    </div>
  );
};

export default EmployeeListPage;

import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Printer, Download, Zap, Wrench, Loader2 } from 'lucide-react';
import { ScheduleOverride } from '../types';
import { loadOverrides } from '../services/storage';
import { BottomMenu } from '../components/BottomMenu';

interface EmployeeBase {
  name: string;
  role: string;
  referenceDate: Date;
  vacations?: { start: Date; end: Date }[];
}

const PrintableCalendarPage: React.FC = () => {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [overrides, setOverrides] = useState<ScheduleOverride[]>([]);
  const [isPreparing, setIsPreparing] = useState(false);

  useEffect(() => {
    const fetch = async () => {
      const data = await loadOverrides();
      setOverrides(data);
    };
    fetch();
  }, []);

  const employeesConfig: EmployeeBase[] = [
    { name: 'Valci Jacinto', role: 'Mecânico', referenceDate: new Date(2025, 11, 1) }, 
    { name: 'Mauro Luiz', role: 'Eletricista', referenceDate: new Date(2025, 11, 1) }, 
    { name: 'Antonio Marcos', role: 'Eletricista', referenceDate: new Date(2025, 11, 2) }, 
    { name: 'Adriano Pinto', role: 'Eletricista', referenceDate: new Date(2025, 11, 3) }, 
    { name: 'Mário de Souza', role: 'Mecânico', referenceDate: new Date(2025, 11, 4) }, 
    { name: 'Manuel Gonçalves', role: 'Mecânico', referenceDate: new Date(2025, 11, 5), vacations: [{ start: new Date(2025, 11, 22), end: new Date(2026, 0, 10) }] }, 
    { name: 'Alan Pereira', role: 'Mecânico', referenceDate: new Date(2025, 11, 6) }, 
  ];

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  const getWhoIsOff = (date: Date) => {
    const list: { name: string, role: string, type: 'regular' | 'vacation' | 'extra' }[] = [];
    const dateStr = date.toISOString().split('T')[0];
    const isEmployeeOnVacation = (employee: EmployeeBase, d: Date) => {
      if (!employee.vacations) return false;
      const target = new Date(d).setHours(0,0,0,0);
      return employee.vacations.some(v => {
        const start = new Date(v.start).setHours(0,0,0,0);
        const end = new Date(v.end).setHours(0,0,0,0);
        return target >= start && target <= end;
      });
    };
    const isRegularDayOff = (employee: EmployeeBase, d: Date) => {
      const target = new Date(d).setHours(0,0,0,0);
      const ref = new Date(employee.referenceDate).setHours(0,0,0,0);
      const diffDays = Math.round((target - ref) / (1000 * 3600 * 24));
      return ((diffDays % 6) + 6) % 6 === 0;
    };
    employeesConfig.forEach(emp => {
      const override = overrides.find(o => o.date === dateStr && o.employeeName === emp.name);
      if (override) { if (override.type === 'extra_day_off') list.push({ name: emp.name, role: emp.role, type: 'extra' }); }
      else if (isEmployeeOnVacation(emp, date)) list.push({ name: emp.name, role: emp.role, type: 'vacation' });
      else if (isRegularDayOff(emp, date)) list.push({ name: emp.name, role: emp.role, type: 'regular' });
    });
    return list;
  };

  const getDaysToRender = () => {
    const daysInMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).getDate();
    const startDay = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).getDay();
    const calendarDays = [];
    for (let i = 0; i < startDay; i++) calendarDays.push(null);
    for (let i = 1; i <= daysInMonth; i++) calendarDays.push(new Date(currentMonth.getFullYear(), currentMonth.getMonth(), i));
    return calendarDays;
  };

  const handlePrint = () => {
    setIsPreparing(true);
    setTimeout(() => { window.print(); setIsPreparing(false); }, 500);
  };

  const calendarDays = getDaysToRender();

  return (
    <div className="flex flex-col h-full bg-[#0f172a] text-white print:bg-white print:text-black">
      <style>{`
        @media print {
          @page { size: A4 landscape; margin: 10mm; }
          body { background: white !important; color: black !important; }
          #root { background: white !important; }
          .no-print { display: none !important; }
          .print-container { width: 100% !important; max-width: none !important; margin: 0 !important; padding: 0 !important; border: none !important; }
          .print-cell { border: 1px solid black !important; background: transparent !important; }
          .print-bg-regular { background-color: #ffedd5 !important; border-left: 5px solid #f97316 !important; }
          .print-bg-vacation { background-color: #dbeafe !important; border-left: 5px solid #3b82f6 !important; }
          .print-bg-extra { background-color: #ccfbf1 !important; border-left: 5px solid #14b8a6 !important; }
          .print-text { color: black !important; font-weight: bold !important; }
        }
      `}</style>
      <div className="flex items-center justify-between px-6 py-4 bg-[#0f172a] border-b border-slate-800 no-print sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1))} className="p-2 hover:bg-slate-800 rounded-full"><ChevronLeft className="w-6 h-6" /></button>
          <h1 className="text-xl font-bold min-w-[200px] text-center">{monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}</h1>
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1))} className="p-2 hover:bg-slate-800 rounded-full"><ChevronRight className="w-6 h-6" /></button>
        </div>
        <button onClick={handlePrint} disabled={isPreparing} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-bold transition-all disabled:opacity-50">
          {isPreparing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
          {isPreparing ? 'Preparando...' : 'Baixar Escala (PDF)'}
        </button>
      </div>
      <div className="print-container flex-1 overflow-auto p-6 flex flex-col gap-6">
        <div className="hidden print:block text-center border-b-2 border-black pb-4 mb-2"><h1 className="text-3xl font-black uppercase">Escala Mensal de Manutenção</h1><p className="text-lg font-bold">{monthNames[currentMonth.getMonth()]} / {currentMonth.getFullYear()}</p></div>
        <div className="flex gap-6 no-print"><div className="flex items-center gap-2 text-[10px] font-bold"><span className="w-3 h-3 bg-orange-500 rounded"></span> FOLGA 5x1</div><div className="flex items-center gap-2 text-[10px] font-bold"><span className="w-3 h-3 bg-blue-500 rounded"></span> FÉRIAS</div><div className="flex items-center gap-2 text-[10px] font-bold"><span className="w-3 h-3 bg-teal-500 rounded"></span> FOLGA EXTRA</div></div>
        <div className="grid grid-cols-7 border-t border-l border-slate-700 print:border-black flex-1 min-h-[600px]">
          {['DOM', 'SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SÁB'].map(day => (<div key={day} className="bg-slate-800/50 py-3 text-center text-xs font-black border-r border-b border-slate-700 print:bg-gray-100 print:border-black print:text-black">{day}</div>))}
          {calendarDays.map((date, idx) => {
            if (!date) return <div key={`empty-${idx}`} className="bg-slate-900/20 border-r border-b border-slate-700 print:border-black"></div>;
            const whoIsOff = getWhoIsOff(date);
            const isToday = new Date().setHours(0,0,0,0) === date.setHours(0,0,0,0);
            return (
              <div key={idx} className={`print-cell p-2 border-r border-b border-slate-700 flex flex-col gap-1 min-h-[120px] bg-slate-900/10 print:min-h-[100px] print:border-black ${isToday ? 'bg-blue-600/10 ring-1 ring-blue-500 ring-inset' : ''}`}>
                <span className={`text-right text-sm font-bold block mb-1 ${isToday ? 'text-blue-500' : 'text-slate-500 print:text-black'}`}>{date.getDate()}</span>
                <div className="flex flex-col gap-1">
                  {whoIsOff.map((off, oIdx) => (
                    <div key={oIdx} className={`text-[9px] px-2 py-1 rounded border-l-2 font-bold uppercase truncate flex items-center gap-1 ${off.type === 'regular' ? 'bg-orange-500/10 text-orange-400 border-orange-500 print-bg-regular print-text' : off.type === 'vacation' ? 'bg-blue-500/10 text-blue-400 border-blue-500 print-bg-vacation print-text' : 'bg-teal-500/10 text-teal-400 border-teal-500 print-bg-extra print-text'}`}>
                      {off.role.toLowerCase().includes('eletricista') ? <Zap className="w-2.5 h-2.5" /> : <Wrench className="w-2.5 h-2.5" />}
                      {off.name.split(' ')[0]}
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>
      <BottomMenu />
    </div>
  );
};

export default PrintableCalendarPage;

