            -webkit-print-color-adjust: exact !important; 
            print-color-adjust: exact !important; 
          }
          .no-print { display: none !important; }
          .print-container { 
            width: 100% !important; 
            margin: 0 !important; 
            padding: 0 !important; 
          }
          .print-grid { 
            border: 1px solid black !important; 
            display: grid !important;
            grid-template-cols: repeat(7, 1fr) !important;
          }
          .print-cell { 
            border: 0.5px solid black !important; 
            min-height: 25mm !important;
            background: white !important;
          }
          .print-bg-regular { background-color: #fff7ed !important; border-left: 4px solid #f97316 !important; }
          .print-bg-vacation { background-color: #eff6ff !important; border-left: 4px solid #3b82f6 !important; }
          .print-bg-extra { background-color: #f0fdfa !important; border-left: 4px solid #14b8a6 !important; }
          .print-text { color: black !important; font-weight: bold !important; }
          #root { background: white !important; }
        }
      `}</style>

      {/* Header de Controle */}
      <div className="flex items-center justify-between px-4 py-4 bg-[#0f172a] border-b border-slate-800 no-print sticky top-0 z-50 shadow-lg pr-14">
        <button 
          onClick={() => navigate(-1)} 
          className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors font-medium px-2 py-1"
        >
          <ArrowLeft className="w-5 h-5" />
          <span className="hidden sm:inline">Voltar</span>
        </button>

        <div className="flex items-center gap-2">
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1))} className="p-1.5 hover:bg-slate-800 rounded-full transition-colors">
            <ChevronLeft className="w-5 h-5" />
          </button>
          <h1 className="text-base font-bold min-w-[150px] text-center">
            {monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}
          </h1>
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1))} className="p-1.5 hover:bg-slate-800 rounded-full transition-colors">
