      const override = overrides.find(o => o.date === dateStr && o.employeeName === emp.name);
      if (override) { if (override.type === 'extra_day_off') list.push({ name: emp.name, role: emp.role, type: 'extra' }); }
      else if (isEmployeeOnVacation(emp, date)) list.push({ name: emp.name, role: emp.role, type: 'vacation' });
      else if (isRegularDayOff(emp, date)) list.push({ name: emp.name, role: emp.role, type: 'regular' });
    });
    return list;
  };

  const getDaysToRender = () => {
    const daysInMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).getDate();
    const startDay = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).getDay();
    const calendarDays = [];
    for (let i = 0; i < startDay; i++) calendarDays.push(null);
    for (let i = 1; i <= daysInMonth; i++) calendarDays.push(new Date(currentMonth.getFullYear(), currentMonth.getMonth(), i));
    return calendarDays;
  };

  const handlePrint = () => {
    setIsPreparing(true);
    const originalTitle = document.title;
    const fileName = `Escala_Manutencao_${monthNames[currentMonth.getMonth()]}_${currentMonth.getFullYear()}`;
    document.title = fileName;

    setTimeout(() => {
      window.print();
      document.title = originalTitle;
      setIsPreparing(false);
    }, 800);
  };

  const calendarDays = getDaysToRender();

  return (
    <div className="flex flex-col h-full bg-[#0f172a] text-white print:bg-white print:text-black min-h-screen transition-colors duration-300">
      <style>{`
        @media print {
          @page { size: A4 landscape; margin: 5mm; }
          body { background: white !important; color: black !important; }
          .no-print { display: none !important; }
          .print-grid { border: 1px solid black !important; display: grid !important; grid-template-columns: repeat(7, 1fr) !important; }
          .print-cell { border: 0.5px solid black !important; min-height: 25mm !important; background: white !important; }
          .print-bg-regular { background-color: #fff7ed !important; border-left: 4px solid #f97316 !important; }
          .print-bg-vacation { background-color: #eff6ff !important; border-left: 4px solid #3b82f6 !important; }
          .print-bg-extra { background-color: #f0fdfa !important; border-left: 4px solid #14b8a6 !important; }
          .print-text { color: black !important; font-weight: bold !important; }
        }
      `}</style>

      {/* Header de Controle */}
      <div className="flex items-center justify-between px-4 py-4 bg-[#0f172a] border-b border-slate-800 no-print sticky top-0 z-50 shadow-lg pr-16">
        <button 
          onClick={() => navigate('/calendar')} 
          className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors font-bold px-3 py-2 rounded-lg hover:bg-slate-800/50"
        >
          <ArrowLeft className="w-5 h-5" />
          <span className="hidden sm:inline">Voltar</span>
        </button>

        <div className="flex items-center gap-2">
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1))} className="p-1.5 hover:bg-slate-800 rounded-full transition-colors">
            <ChevronLeft className="w-5 h-5" />
          </button>
          <h1 className="text-base font-bold min-w-[150px] text-center">
            {monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}
          </h1>
          <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1))} className="p-1.5 hover:bg-slate-800 rounded-full transition-colors">
            <ChevronRight className="w-5 h-5" />
          </button>
        </div>

        <button 
          onClick={handlePrint}
          disabled={isPreparing}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm"
        >
          {isPreparing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
          {isPreparing ? 'Gerando...' : 'Baixar PDF'}
        </button>
      </div>

      <div className="print-container flex-1 overflow-auto p-6 flex flex-col gap-4">
        {/* Título Visível Apenas no PDF */}
        <div className="hidden print:block text-center border-b-2 border-black pb-4 mb-4">
          <h1 className="text-3xl font-black uppercase tracking-tight">Escala Mensal de Folgas - Manutenção</h1>
          <p className="text-lg font-bold text-slate-700">{monthNames[currentMonth.getMonth()]} de {currentMonth.getFullYear()}</p>
        </div>

        {/* Legenda */}
        <div className="flex gap-6 no-print mb-2 justify-center">
          <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider text-slate-400">
            <span className="w-3 h-3 bg-orange-500 rounded"></span> Folga 5x1
          </div>
          <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider text-slate-400">
            <span className="w-3 h-3 bg-blue-500 rounded"></span> Férias
          </div>
          <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider text-slate-400">
            <span className="w-3 h-3 bg-teal-500 rounded"></span> Extra
          </div>
        </div>

        {/* Grid do Calendário */}
        <div className="print-grid grid grid-cols-7 border-t border-l border-slate-700 flex-1 min-h-[500px] rounded-lg overflow-hidden border-slate-700">
          {['DOM', 'SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SÁB'].map(day => (
            <div key={day} className="bg-slate-800/80 py-3 text-center text-[10px] font-black border-r border-b border-slate-700 print:bg-slate-100 print:text-black print:border-black uppercase tracking-widest">
              {day}
            </div>
          ))}

          {calendarDays.map((date, idx) => {
            if (!date) return <div key={`empty-${idx}`} className="bg-slate-900/20 border-r border-b border-slate-700 print:border-black"></div>;

            const whoIsOff = getWhoIsOff(date);
            const isToday = new Date().setHours(0,0,0,0) === date.setHours(0,0,0,0);

            return (
              <div key={idx} className={`print-cell p-2 border-r border-b border-slate-700 flex flex-col gap-1 min-h-[110px] bg-slate-900/10 print:border-black ${isToday ? 'bg-blue-600/5 ring-1 ring-blue-500/50 ring-inset' : ''}`}>
                <span className={`text-right text-xs font-black block mb-1 ${isToday ? 'text-blue-500' : 'text-slate-500 print:text-black'}`}>
                  {date.getDate()}
                </span>

                <div className="flex flex-col gap-1 overflow-hidden">
                  {whoIsOff.map((off, oIdx) => (
                    <div 
                      key={oIdx} 
                      className={`text-[9px] px-2 py-1.5 rounded border-l-2 font-bold uppercase truncate flex items-center gap-1 shadow-sm
                        ${off.type === 'regular' ? 'bg-orange-500/10 text-orange-400 border-orange-500 print-bg-regular print-text' : 
                          off.type === 'vacation' ? 'bg-blue-500/10 text-blue-400 border-blue-500 print-bg-vacation print-text' : 
                          'bg-teal-500/10 text-teal-400 border-teal-500 print-bg-extra print-text'}
                      `}
                    >
                      {off.role.toLowerCase().includes('eletricista') ? <Zap className="w-2.5 h-2.5 flex-shrink-0" /> : <Wrench className="w-2.5 h-2.5 flex-shrink-0" />}
                      <span className="truncate">{formatDisplayName(off.name)}</span>
                    </div>
